import pandas as pd
import re
import ast
from collections import defaultdict, Counter

# Load patent data
patent_file = locals()['var_functions.query_db:2']
with open(patent_file, 'r') as f:
    patent_data = json.load(f)

# Get CPC codes from patents and analyze their structure
cpc_prefixes = Counter()
for record in patent_data:
    cpc_str = record.get('cpc', '')
    if not cpc_str:
        continue
    try:
        cpc_list = ast.literal_eval(cpc_str)
        for cpc_entry in cpc_list:
            if isinstance(cpc_entry, dict) and 'code' in cpc_entry:
                code = cpc_entry['code']
                if len(code) >= 4:
                    cpc_prefixes[code[:4]] += 1
    except:
        pass

print("Most common CPC prefixes in patents:")
for prefix, count in cpc_prefixes.most_common(20):
    print(f"  {prefix}: {count}")

# Load level 5 CPC symbols
cpc_file = locals()['var_functions.query_db:3']
with open(cpc_file, 'r') as f:
    cpc_level5_data = json.load(f)
cpc_symbols = set(item['symbol'] for item in cpc_level5_data)

print(f"\nTotal unique CPC prefixes in patents: {len(cpc_prefixes)}")
print(f"Total level 5 CPC symbols: {len(cpc_symbols)}")

# Check overlap
overlap = cpc_prefixes.keys() & cpc_symbols
print(f"Overlapping prefixes: {len(overlap)}")

if overlap:
    print("\nSample overlapping prefixes:")
    for prefix in list(overlap)[:10]:
        print(f"  {prefix}: {cpc_prefixes[prefix]}")
else:
    print("\nNo overlap found! Checking sample symbols...")
    print("Sample level 5 symbols:", list(cpc_symbols)[:10])
    print("Sample patent prefixes:", list(cpc_prefixes.keys())[:10])

# Process for 2022 specifically
cpc_2022 = Counter()
for record in patent_data:
    pub_date = record.get('publication_date', '')
    if '2022' not in str(pub_date):
        continue

    cpc_str = record.get('cpc', '')
    if not cpc_str:
        continue
    try:
        cpc_list = ast.literal_eval(cpc_str)
        for cpc_entry in cpc_list:
            if isinstance(cpc_entry, dict) and 'code' in cpc_entry:
                code = cpc_entry['code']
                if len(code) >= 4:
                    prefix = code[:4]
                    if prefix in cpc_symbols:
                        cpc_2022[prefix] += 1
    except:
        pass

print(f"\nCPC groups with patents in 2022 that match level 5 symbols: {len(cpc_2022)}")
if cpc_2022:
    print("Top groups in 2022:")
    for group, count in cpc_2022.most_common(10):
        print(f"  {group}: {count}")
else:
    print("No matching CPC groups found for 2022!")

print('__RESULT__:')
print(json.dumps({"diagnostic": "complete"}))"}

