# Check overlap
overlap = cpc_prefixes.keys() & cpc_symbols
print(f"Overlapping prefixes: {len(overlap)}")

if overlap:
    print("\nSample overlapping prefixes:")
    for prefix in list(overlap)[:10]:
        print(f"  {prefix}: {cpc_prefixes[prefix]}")
else:
